export type FlowNodeType = typeof FlowNodeType[keyof typeof FlowNodeType];


export const FlowNodeType = {
  trigger: 'trigger',
  message: 'message',
  question: 'question',
  end: 'end',
  ai: 'ai',
  products: 'products',
} as const;

export type FlowNodePosition = {
  x: number;
  y: number;
};

export type FlowNodeDataMatchType = typeof FlowNodeDataMatchType[keyof typeof FlowNodeDataMatchType];


export const FlowNodeDataMatchType = {
  default: 'default',
  keyword: 'keyword',
} as const;

export type FlowNodeDataOptionsItem = {
  id: string;
  label: string;
};

export type FlowNodeData = {
  matchType?: FlowNodeDataMatchType;
  keywords?: string[];
  text?: string;
  /**
     * Message/Question only: optional image URL (http(s) or /api/media/...) sent with the text as caption.
     * @nullable
     */
  imageUrl?: string | null;
  options?: FlowNodeDataOptionsItem[];
  /** Question only: re-ask question on off-option replies instead of handing off to AI. */
  strictOptions?: boolean;
  /** Question only: when strictOptions=true, this message is sent before the question is re-asked. Leave empty to skip. */
  strictRetryMessage?: string;
  /** Question only: when true, the question text is rephrased by AI (same meaning, varied natural wording) each time it is sent, so it doesn't feel like a canned bot message. Answer options are never rephrased. */
  aiRephrase?: boolean;
  /** Products only: list of product IDs to send (image + Nama/Kode/Harga caption). */
  productIds?: number[];
  /** AI node only: extra instruction appended to the global AI Studio system prompt while this node's AI handoff is active (during the flow cooldown). Empty = use the global prompt only. */
  aiInstruction?: string;
  /** AI node only: restrict the AI's knowledge-base reference to these specific knowledge entry IDs while this node's handoff is active. Empty = use all of the owner's knowledge base. */
  knowledgeIds?: number[];
};

export interface FlowNode {
  id: string;
  type: FlowNodeType;
  position: FlowNodePosition;
  data: FlowNodeData;
}

export interface FlowEdge {
  id: string;
  source: string;
  target: string;
  /** @nullable */
  sourceHandle?: string | null;
}

export interface FlowGraph {
  nodes: FlowNode[];
  edges: FlowEdge[];
}

